import { useState, useRef, useEffect } from 'react'
import { supportedLangs, langOptions } from '../i18n/translations'
import { ucWords } from '../utils/ucWords'
import './Footer.css'

/** Footer: optional CMS-driven columns from `footerNavTree` (parent pages + children); else static link columns. */
export default function Footer({ lang, t, footerNavTree = [] }) {
  const [langOpen, setLangOpen] = useState(false)
  const langRef = useRef(null)
  const showLangSwitcher = supportedLangs.length > 1

  useEffect(() => {
    function handleClickOutside(e) {
      if (langRef.current && !langRef.current.contains(e.target)) setLangOpen(false)
    }
    if (langOpen) {
      document.addEventListener('click', handleClickOutside)
      return () => document.removeEventListener('click', handleClickOutside)
    }
  }, [langOpen])

  const langPrefix = supportedLangs.includes(lang) ? lang : 'en'

  const hasCmsColumns = Array.isArray(footerNavTree) && footerNavTree.length > 0

  return (
    <footer className="footer footer--dark">
      <div className="footer-inner">
        <div className="footer-main">
          <div className="footer-brand">
            <a href="/" className="footer-brand-logo" aria-label={t('nav.home')}>
              <img
                className="footer-brand-img"
                src="/logos/apimstec.png"
                alt=""
                width={160}
                height={48}
                decoding="async"
              />
            </a>
            <p className="footer-brand-tagline">{t('footerTagline')}</p>
          </div>

          <div className="footer-nav-grid">
            {hasCmsColumns
              ? footerNavTree.map((root) => (
                <div key={root.id} className="footer-col">
                  <h3 className="footer-col-title">{ucWords(root.title)}</h3>
                  {root.children && root.children.length > 0 ? (
                    root.children.map((c) => (
                      <a key={c.id} href={`/page/${c.slug}`}>{ucWords(c.title)}</a>
                    ))
                  ) : (
                    <a href={`/page/${root.slug}`}>{ucWords(root.title)}</a>
                  )}
                </div>
              ))
              : (
                <>
                  <div className="footer-col">
                    <h3 className="footer-col-title">{t('footerProduct')}</h3>
                    <a href="/">{t('footerHome')}</a>
                    <a href="/platform">{t('nav.platform')}</a>
                    <a href="/marketplace">{t('nav.marketplace')}</a>
                    <a href="/consultancy">{t('nav.consultancy')}</a>
                    <a href="/solutions">{t('nav.solutions')}</a>
                    <a href="/insights">{t('nav.insights')}</a>
                  </div>
                  <div className="footer-col">
                    <h3 className="footer-col-title">{t('footerResources')}</h3>
                    <a href="/blog">{t('footerBlog')}</a>
                    <a href="/insights">{t('nav.insights')}</a>
                    <a href="/about/news">{t('footerPress')}</a>
                  </div>
                  <div className="footer-col">
                    <h3 className="footer-col-title">{t('footerCompany')}</h3>
                    <a href="/about">{t('footerAbout')}</a>
                    <a href="/about/careers">{t('corporate.footerCareers')}</a>
                    <a href="/contact">{t('footerContact')}</a>
                  </div>
                </>
              )}

            <div className="footer-col footer-col--contact">
              <h3 className="footer-col-title">{t('footerContact')}</h3>
              <a href="/contact">{t('footerContact')}</a>
              <p className="footer-connect-label">{t('footerConnect')}</p>
              <nav className="footer-social" aria-label="Social links">
                <a href="#twitter" aria-label="X (Twitter)"><span className="footer-social-icon">𝕏</span></a>
                <a href="#linkedin" aria-label="LinkedIn"><span className="footer-social-icon">in</span></a>
                <a href="#facebook" aria-label="Facebook"><span className="footer-social-icon">f</span></a>
                <a href="#youtube" aria-label="YouTube"><span className="footer-social-icon">▶</span></a>
              </nav>
            </div>

            <div className="footer-col">
              <h3 className="footer-col-title">{t('footerLegal')}</h3>
              <a href="/page/privacy">{t('footerPrivacy')}</a>
              <a href="/page/terms">{t('footerTerms')}</a>
            </div>
          </div>
        </div>

        <div className="footer-divider" />

        <div className="footer-bottom">
          {showLangSwitcher ? (
            <div className="footer-lang-wrap" ref={langRef}>
              <button
                type="button"
                className="footer-lang-btn"
                onClick={() => setLangOpen((o) => !o)}
                aria-expanded={langOpen}
                aria-haspopup="listbox"
                aria-label="Select language"
              >
                <span className="footer-lang-icon" aria-hidden>🌐</span>
                <span>{langOptions[langPrefix]?.label || t('footerLanguage')}</span>
                <span className="footer-lang-chevron" aria-hidden>▼</span>
              </button>
              {langOpen && (
                <ul className="footer-lang-menu" role="listbox">
                  {supportedLangs.map((l) => (
                    <li key={l} role="option">
                      <span className="footer-lang-item">
                        {langOptions[l]?.label || l.toUpperCase()}
                      </span>
                    </li>
                  ))}
                </ul>
              )}
            </div>
          ) : null}
          <div className="footer-bottom-right">
            <p className="footer-copy">{t('footerCopyright')}</p>
            <nav className="footer-legal-links" aria-label="Legal">
              <a href="/page/terms">{t('footerTerms')}</a>
              <span className="footer-legal-sep" aria-hidden>|</span>
              <a href="/page/privacy">{t('footerPrivacy')}</a>
            </nav>
          </div>
        </div>
      </div>
    </footer>
  )
}
